import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Motor de Screening: Analisa a 'Vida' de uma cidade específica na malha.
 */
export const performCommunityScreening = async (cityName: string): Promise<any> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Faça um 'Screening' da cidade de ${cityName}, Pernambuco, na BR-232. 
      Analise: Economia local, Eventos e Pulse (humor da cidade).
      Responda estritamente em JSON.`,
      config: { 
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            economy: { type: Type.STRING },
            events: { type: Type.STRING },
            pulse: { type: Type.STRING },
            opportunities: { type: Type.STRING }
          },
          required: ["economy", "events", "pulse", "opportunities"]
        }
      },
    });
    return JSON.parse(response.text);
  } catch (error) {
    return { 
      economy: "Dados locais em atualização.", 
      events: "Consulte o calendário da praça.", 
      pulse: "Cidade em fluxo normal.", 
      opportunities: "Potencial logístico alto." 
    };
  }
};

/**
 * Agente de Hermenêutica: Analisa feedbacks para medir discrição e ética.
 */
export const analyzePilotFeedback = async (feedbacks: string[]): Promise<number> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Analise a ética destes feedbacks de pilotos na BR-232: "${feedbacks.join(' | ')}".
      Retorne APENAS um número de 0 a 1 para o 'Fator Discrição'.`,
    });
    const score = parseFloat(response.text.trim());
    return isNaN(score) ? 0.5 : score;
  } catch (error) {
    return 0.5;
  }
};

/**
 * Busca notícias REAIS focadas exclusivamente na BR-232.
 */
export const getRealTimeRoadNews = async (): Promise<{ summary: string; sources: { title: string; uri: string }[] }> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `O que está acontecendo agora na rodovia BR-232 em Pernambuco? Foque em alertas reais.`,
      config: { tools: [{ googleSearch: {} }] },
    });
    const summary = response.text || "Fluxo normal na Luiz Gonzaga.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources = chunks.filter((chunk: any) => chunk.web).map((chunk: any) => ({
      title: chunk.web.title,
      uri: chunk.web.uri
    }));
    return { summary, sources };
  } catch (error) {
    return { summary: "Sem alertas críticos registrados.", sources: [] };
  }
};

/**
 * Analisa o status da rodovia baseado nos alertas locais.
 */
export const analyzeRoadStatus = async (alerts: any[]): Promise<{ status: string; color: string; advice: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analise estes incidentes: ${JSON.stringify(alerts)}. Retorne JSON com status, color (HEX) e advice regional.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            color: { type: Type.STRING },
            advice: { type: Type.STRING }
          },
          required: ["status", "color", "advice"]
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    return { status: "Livre", color: "#1e4d8c", advice: "Vá na paz, boy!" };
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';

// Pages
import Welcome from './pages/Welcome';
import Login from './pages/Login';
import Home from './pages/Home';
import Alerts from './pages/Alerts';
import Classifieds from './pages/Classifieds';
import CommunityLife from './pages/CommunityLife';
import Blog from './pages/Blog';
import Patrons from './pages/Patrons';
import ReportAlert from './pages/ReportAlert';
import MotoTaxi from './pages/MotoTaxi';
import PostAd from './pages/PostAd';
import Roadmap from './pages/Roadmap';
import Profile from './pages/Profile';
import Verify from './pages/Verify';
import AdminDashboard from './pages/AdminDashboard';
import Terms from './pages/Terms';
import Manifesto from './pages/Manifesto';

// Components
import ContextBar from './components/ContextBar';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('ecobr232_auth') === 'true';
  });

  const login = () => {
    localStorage.setItem('ecobr232_auth', 'true');
    setIsAuthenticated(true);
  };

  const logout = () => {
    localStorage.removeItem('ecobr232_auth');
    setIsAuthenticated(false);
  };

  return (
    <Router>
      <div className="min-h-screen bg-background-light dark:bg-background-dark transition-colors font-display">
        <SafetyGuard />
        <Routes>
          <Route path="/" element={<Welcome />} />
          <Route path="/login" element={<Login onLogin={login} />} />
          <Route path="/verify" element={<Verify />} />
          <Route path="/termos" element={<Terms />} />
          <Route path="/manifesto" element={<Manifesto />} />

          <Route path="/dashboard" element={<Layout><Home /></Layout>} />
          <Route path="/alertas" element={<Layout><Alerts /></Layout>} />
          <Route path="/classificados" element={<Layout><Classifieds /></Layout>} />
          <Route path="/vida" element={<Layout><CommunityLife /></Layout>} />
          <Route path="/blog" element={<Layout><Blog /></Layout>} />
          <Route path="/moto-taxi" element={<Layout><MotoTaxi /></Layout>} />
          <Route path="/patronos" element={<Layout><Patrons /></Layout>} />
          <Route path="/roadmap" element={<Layout><Roadmap /></Layout>} />

          <Route path="/perfil" element={
            isAuthenticated ? <Layout><Profile onLogout={logout} /></Layout> : <Navigate to="/login" />
          } />

          <Route path="/reportar" element={<ReportAlert />} />
          <Route path="/anunciar" element={<PostAd />} />
          <Route path="/admin" element={<AdminDashboard />} />
        </Routes>
      </div>
    </Router>
  );
};

const SafetyGuard: React.FC = () => {
  const [speedAlert, setSpeedAlert] = useState(false);

  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => {
        const speed = pos.coords.speed || 0;
        // 15 m/s é aproximadamente 54 km/h
        if (speed > 15) setSpeedAlert(true);
        else setSpeedAlert(false);
      },
      () => {},
      { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  if (!speedAlert) return null;

  return (
    <div className="fixed inset-0 z-[9999] bg-[#e31d24] flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-300">
      <span className="material-symbols-outlined text-[120px] text-white mb-6 filled">front_hand</span>
      <h2 className="text-white text-3xl font-black mb-4 italic uppercase">Vixe! Tá correndo é?</h2>
      <p className="text-white/90 text-lg font-bold leading-relaxed mb-8">
        Pare a bexiga do carro num lugar seguro pra mexer no celular, visse?
      </p>
      <button onClick={() => setSpeedAlert(false)} className="px-8 py-4 bg-white text-[#e31d24] rounded-2xl font-black uppercase shadow-2xl">
        Já parei, pode liberar!
      </button>
    </div>
  );
};

const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  return (
    <div className="flex flex-col min-h-screen pb-32">
      <main className="flex-1">
        {children}
      </main>
      <ContextBar />
      <BottomNav />
    </div>
  );
};

const BottomNav: React.FC = () => {
  const location = useLocation();

  return (
    <nav className="fixed bottom-0 w-full bg-white dark:bg-[#161e31] border-t border-slate-200 dark:border-white/5 pb-8 pt-4 z-50 shadow-2xl">
      <ul className="flex justify-around items-end px-4 max-w-lg mx-auto">
        <NavItem to="/dashboard" icon="home" label="Início" active={location.pathname === '/dashboard'} />
        <NavItem to="/alertas" icon="map" label="Mapa" active={location.pathname === '/alertas'} />
        <NavItem to="/vida" icon="favorite" label="Vida" active={location.pathname === '/vida'} />
        <NavItem to="/classificados" icon="explore" label="Feira" active={location.pathname === '/classificados'} />
        <NavItem to="/perfil" icon="person" label="Perfil" active={location.pathname === '/perfil'} />
      </ul>
    </nav>
  );
};

const NavItem: React.FC<{ to: string; icon: string; label: string; active: boolean }> = ({ to, icon, label, active }) => (
  <li className="flex-1">
    <Link to={to} className={`flex flex-col items-center gap-1.5 transition-all ${active ? 'text-[#1e4d8c]' : 'text-slate-400 hover:text-[#1e4d8c]'}`}>
      <span className={`material-symbols-outlined text-[30px] ${active ? 'filled' : ''}`}>{icon}</span>
      <span className="text-[10px] font-bold uppercase tracking-tight">{label}</span>
    </Link>
  </li>
);

export default App;

export interface StoredAd {
  id: string;
  title: string;
  category: string;
  city: string;
  price?: string;
  img: string;
  isPremium: boolean;
  isVerified: boolean;
  createdAt: number;
  rating: number;
  userId: string;
}

export interface StoredAlert {
  id: string;
  type: string;
  km: number;
  location: string;
  timestamp: number;
  userId: string;
}

export interface ReferralStats {
  referralCode: string;
  totalReferrals: number;
  pendingCredits: number;
  adCredits: number;
  commissionRate: number;
  campaignStart: number;
  campaignDurationDays: number;
  benefitExpiryMonths: number;
}

const STORAGE_KEYS = {
  ADS: 'ecobr232_ads',
  ALERTS: 'ecobr232_alerts',
  USER_STATS: 'ecobr232_referral_stats'
};

const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

export const db = {
  ads: {
    async getAll(): Promise<StoredAd[]> {
      const data = localStorage.getItem(STORAGE_KEYS.ADS);
      return data ? JSON.parse(data) : [];
    },
    async save(ad: Omit<StoredAd, 'id' | 'createdAt' | 'rating' | 'isVerified'>): Promise<StoredAd> {
      await delay(500);
      const ads = await this.getAll();
      const newAd: StoredAd = {
        ...ad,
        id: Math.random().toString(36).substr(2, 9),
        createdAt: Date.now(),
        rating: 5.0,
        isVerified: false
      };
      localStorage.setItem(STORAGE_KEYS.ADS, JSON.stringify([newAd, ...ads]));
      return newAd;
    },
    async delete(id: string): Promise<void> {
      const ads = await this.getAll();
      const filtered = ads.filter(a => a.id !== id);
      localStorage.setItem(STORAGE_KEYS.ADS, JSON.stringify(filtered));
    }
  },
  alerts: {
    async getAll(): Promise<StoredAlert[]> {
      const data = localStorage.getItem(STORAGE_KEYS.ALERTS);
      return data ? JSON.parse(data) : [];
    },
    async save(alert: Omit<StoredAlert, 'id' | 'timestamp'>): Promise<StoredAlert> {
      await delay(500);
      const alerts = await this.getAll();
      const newAlert: StoredAlert = {
        ...alert,
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now()
      };
      localStorage.setItem(STORAGE_KEYS.ALERTS, JSON.stringify([newAlert, ...alerts]));
      return newAlert;
    }
  },
  referrals: {
    async getStats(): Promise<ReferralStats> {
      const data = localStorage.getItem(STORAGE_KEYS.USER_STATS);
      if (data) return JSON.parse(data);

      const defaultStats: ReferralStats = {
        referralCode: 'ADM-232',
        totalReferrals: 0,
        pendingCredits: 0,
        adCredits: 0,
        commissionRate: 0.10,
        campaignStart: Date.now(),
        campaignDurationDays: 30,
        benefitExpiryMonths: 24
      };
      localStorage.setItem(STORAGE_KEYS.USER_STATS, JSON.stringify(defaultStats));
      return defaultStats;
    }
  },
  system: {
    async resetAll(): Promise<void> {
      localStorage.clear();
    }
  }
};

