        <span className={`font-black italic text-lg leading-tight tracking-tighter ${variant === 'white' ? 'text-white' : 'text-[#1e4d8c] dark:text-white'}`}>
          BR<span className="text-[#e31d24]">232</span>
        </span>
      </div>
    </div>
  );
};

export default Logo;

