  const [activeStep, setActiveStep] = useState(1);

  useEffect(() => {
    db.referrals.getStats().then(s => setStats(s));

    const updateTimer = () => {
      const blitzStart = new Date();
      blitzStart.setHours(12, 0, 0, 0);
      const deadline = new Date(blitzStart.getTime() + (30 * 24 * 60 * 60 * 1000));
      const now = new Date();
      const diff = deadline.getTime() - now.getTime();

      if (diff <= 0) {
        setTimeLeft({ d: 0, h: 0, m: 0, s: 0 });
        return;
      }

      setTimeLeft({
        d: Math.floor(diff / (1000 * 60 * 60 * 24)),
        h: Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        m: Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60)),
        s: Math.floor((diff % (1000 * 60)) / 1000)
      });
    };

    updateTimer();
    const interval = setInterval(updateTimer, 1000);
    return () => clearInterval(interval);
  }, []);

  const getShareData = () => {
    const shareUrl = `${window.location.origin}/#/login?ref=${stats?.referralCode}`;
    const shareText = `🏁 *SERVIÇO BR-232: EARLY ADOPTER* 🏁\n\nConsegui uma chave de acesso para você testar os serviços da nossa rodovia!\n\n⚠️ *JANELA DE 30 DIAS:* \n- 50% de DESCONTO em anúncios (Fixo 2 anos)\n- Ganhe CRÉDITOS por cada novo parceiro indicado\n\n✅ CHAVE DE ACESSO: *${stats?.referralCode}*\n🔗 ACESSAR SERVIÇO: ${shareUrl}\n\n_Operação Blitz na Pista!_ 🚀🛣️`;
    return { shareUrl, shareText };
  };

  const handleShareWhatsApp = () => {
    const { shareText } = getShareData();
    window.open(`https://wa.me/?text=${encodeURIComponent(shareText)}`, '_blank');
  };

  const handleCopyLink = () => {
    const { shareUrl } = getShareData();
    navigator.clipboard.writeText(shareUrl);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="bg-background-dark min-h-screen p-4 pb-32 font-display text-white">
      <header className="pt-8 pb-6 text-center space-y-4">
        <div className="relative inline-block">
          <div className="absolute -inset-2 bg-gradient-to-r from-[#1e4d8c] to-[#e31d24] rounded-full blur-xl opacity-20"></div>
          <div className="relative size-28 rounded-full bg-cover bg-center border-4 border-surface-dark shadow-2xl" style={{ backgroundImage: "url('https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&q=80&w=200')" }}></div>
