      </div>

      {/* MODAL DE RECRUTAMENTO - GUIA DE SERVIÇO */}
      {showInviteModal && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-md flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="relative w-full max-w-sm bg-surface-dark rounded-[3rem] border border-white/10 overflow-hidden shadow-2xl flex flex-col">

            <div className="p-6 pb-2 flex items-center justify-between">
               <div className="flex items-center gap-2">
                  <Zap size={16} className="text-[#e31d24]" />
                  <span className="text-[10px] font-black uppercase tracking-widest">Guia do Piloto Early Adopter</span>
               </div>
               <button onClick={() => setShowInviteModal(false)} className="size-10 bg-white/5 rounded-full flex items-center justify-center">
                  <X size={20} />
               </button>
            </div>

            <div className="p-8 flex flex-col gap-6">
               {activeStep === 1 && (
