import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Zap, ShieldCheck, ChevronRight, Timer, BadgeCheck, Sparkles } from 'lucide-react';
import { db } from '../services/db';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const navigate = useNavigate();
  const location = useLocation();
  const [adminId, setAdminId] = useState('');
  const [referralCode, setReferralCode] = useState<string | null>(null);
  const [timeLeft, setTimeLeft] = useState({ d: 0, h: 0, m: 0, s: 0 });

  useEffect(() => {
    const searchParams = new URLSearchParams(window.location.search || window.location.hash.split('?')[1]);
    const ref = searchParams.get('ref');

    if (ref) {
      setReferralCode(ref);
    }

    const updateTimer = () => {
      const blitzStart = new Date();
      blitzStart.setHours(12, 0, 0, 0);
      const deadline = new Date(blitzStart.getTime() + (30 * 24 * 60 * 60 * 1000));
      const now = new Date();
      const diff = deadline.getTime() - now.getTime();

      if (diff <= 0) {
        setTimeLeft({ d: 0, h: 0, m: 0, s: 0 });
        return;
      }

      setTimeLeft({
        d: Math.floor(diff / (1000 * 60 * 60 * 24)),
        h: Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        m: Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60)),
        s: Math.floor((diff % (1000 * 60)) / 1000)
      });
    };

    updateTimer();
    const interval = setInterval(updateTimer, 1000);
    return () => clearInterval(interval);
  }, [location]);

  const handleLoginAction = async () => {
    if (referralCode) {
      const stats = await db.referrals.getStats();
      const newStats = {
        ...stats,
        totalReferrals: (stats.totalReferrals || 0) + 1,
        adCredits: (stats.adCredits || 0) + 50.00
      };
      localStorage.setItem('ecobr232_referral_stats', JSON.stringify(newStats));
    }

    onLogin();
    navigate('/verify');
  };

  const handleAdminAccess = () => {
    if (adminId.toUpperCase() === 'ADM-232') {
      navigate('/admin');
    } else {
      alert('Acesso negado à Central de Comando.');
    }
  };

  return (
    <div className="relative min-h-screen w-full bg-background-dark font-display flex flex-col items-center justify-center overflow-hidden text-white">

      <div className="absolute inset-0 z-0">
        <div className="absolute inset-0 bg-black/80 z-10"></div>
        <img 
          src="https://images.unsplash.com/photo-1511919884226-fd3cad34687c?auto=format&fit=crop&q=80&w=1200" 
          className="w-full h-full object-cover scale-110 brightness-50"
          alt=""
        />
      </div>

      <div className="relative z-20 w-full max-w-md px-6 flex flex-col items-center">

        {/* Banner de Convite Ativo */}
        {referralCode && (
          <div className="mb-8 w-full p-5 bg-gradient-to-r from-[#1e4d8c]/30 to-[#e31d24]/30 backdrop-blur-2xl border border-white/10 rounded-[2rem] flex items-center gap-4 animate-in zoom-in duration-700 shadow-2xl">
             <div className="size-14 bg-white rounded-2xl flex items-center justify-center shadow-xl">
                <Sparkles size={28} className="text-[#1e4d8c]" />
             </div>
             <div>
                <p className="text-[10px] font-black uppercase tracking-widest text-[#1e4d8c]">Convite Detectado</p>
                <p className="text-sm font-black text-white italic">Benefícios Early Adopter Ativados!</p>
             </div>
          </div>
        )}

        <div className="mb-6 flex items-center gap-3 px-6 py-2 rounded-full bg-[#e31d24]/10 border border-[#e31d24]/30 backdrop-blur-xl">
           <Zap size={14} className="text-[#e31d24] animate-pulse" fill="currentColor" />
           <span className="text-[10px] font-black uppercase tracking-[0.4em] text-white italic">Operação Blitz 30 Dias</span>
        </div>

        <div className="text-center mb-10">
           <h1 className="text-6xl font-black italic uppercase tracking-tighter leading-none mb-2">
             Entrar na <br/>
             <span className="text-[#1e4d8c]">Malha</span>
           </h1>
           <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em]">Acesso ao Serviço Early Adopter</p>
        </div>

        <div className="w-full bg-white/5 backdrop-blur-3xl border border-white/5 rounded-[3rem] p-10 mb-10 text-center shadow-inner">
             <div className="flex justify-between items-center">
                <TimeCell value={timeLeft.d} label="Dias" />
                <div className="h-8 w-px bg-white/10"></div>
                <TimeCell value={timeLeft.h} label="Horas" />
                <div className="h-8 w-px bg-white/10"></div>
                <TimeCell value={timeLeft.m} label="Mins" />
                <div className="h-8 w-px bg-white/10"></div>
                <TimeCell value={timeLeft.s} label="Segs" color="text-[#e31d24]" />
             </div>
        </div>

        <button 
          onClick={handleLoginAction}
          className="group relative w-full h-24 bg-white rounded-[2rem] shadow-2xl active:scale-[0.98] transition-all overflow-hidden"
        >
          <div className="absolute inset-0 bg-gradient-to-r from-transparent via-[#1e4d8c]/5 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
          <div className="relative flex items-center justify-center gap-4 h-full">
            <span className="text-slate-900 text-2xl font-black uppercase italic">Validar Acesso</span>
            <ChevronRight className="text-[#1e4d8c] group-hover:translate-x-2 transition-transform" size={28} />
          </div>
        </button>

        <div className="mt-14 w-full pt-8 border-t border-white/5 flex flex-col items-center">
           <div className="flex gap-3 w-full max-w-[260px]">
              <input 
                value={adminId}
                onChange={(e) => setAdminId(e.target.value)}
                className="flex-1 bg-black/40 border border-white/10 rounded-2xl h-14 px-5 text-[10px] font-black uppercase tracking-widest outline-none focus:border-[#1e4d8c]/50 text-center transition-all" 
                placeholder="TOKEN DE SERVIÇO" 
              />
              <button onClick={handleAdminAccess} className="size-14 bg-white/5 rounded-2xl flex items-center justify-center border border-white/10 hover:bg-white/10 transition-colors">
                 <ShieldCheck size={20} className="text-[#1e4d8c]" />
              </button>
           </div>
        </div>
      </div>
    </div>
  );
};

const TimeCell: React.FC<{ value: number; label: string; color?: string }> = ({ value, label, color = "text-white" }) => (
  <div className="flex flex-col items-center flex-1">
    <span className={`text-3xl font-black italic tracking-tighter ${color}`}>{value.toString().padStart(2, '0')}</span>
    <span className="text-[7px] font-black uppercase text-white/30 tracking-[0.2em] mt-2">{label}</span>
  </div>
);

export default Login;

