import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Zap, ShieldCheck, ChevronRight, Timer, Sparkles } from 'lucide-react';
import { db } from '../services/db';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const navigate = useNavigate();
  const location = useLocation();
  const [adminId, setAdminId] = useState('');
  const [referralCode, setReferralCode] = useState<string | null>(null);
  const [timeLeft, setTimeLeft] = useState({ d: 0, h: 0, m: 0, s: 0 });

  useEffect(() => {
    // Captura o código de indicação de forma resiliente para o teste
    const getRef = () => {
      const params = new URLSearchParams(window.location.search);
      if (params.get('ref')) return params.get('ref');
      const hashParts = window.location.hash.split('?');
      if (hashParts.length > 1) {
        return new URLSearchParams(hashParts[1]).get('ref');
      }
      return null;
    };

    const ref = getRef();
    if (ref) setReferralCode(ref);

    const updateTimer = () => {
      const start = new Date();
      start.setHours(12, 0, 0, 0);
      const deadline = new Date(start.getTime() + (30 * 24 * 60 * 60 * 1000));
      const diff = deadline.getTime() - new Date().getTime();
      if (diff <= 0) return;
      setTimeLeft({
        d: Math.floor(diff / (1000 * 60 * 60 * 24)),
        h: Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        m: Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60)),
        s: Math.floor((diff % (1000 * 60)) / 1000)
      });
    };
    updateTimer();
    const interval = setInterval(updateTimer, 1000);
    return () => clearInterval(interval);
  }, [location]);

  const handleActivation = async () => {
    if (referralCode) {
      const stats = await db.referrals.getStats();
      localStorage.setItem('ecobr232_referral_stats', JSON.stringify({
        ...stats,
        totalReferrals: (stats.totalReferrals || 0) + 1,
        adCredits: (stats.adCredits || 0) + 50.00
      }));
    }
    onLogin();
    navigate('/verify');
  };

  return (
    <div className="relative min-h-screen w-full bg-[#0a0f1d] font-display flex flex-col items-center justify-center overflow-hidden text-white">
      <div className="absolute inset-0 opacity-20">
        <img src="https://images.unsplash.com/photo-1511919884226-fd3cad34687c?auto=format&fit=crop&q=80&w=1200" className="w-full h-full object-cover" alt="" />
      </div>

      <div className="relative z-20 w-full max-w-md px-6 flex flex-col items-center">
        {referralCode && (
          <div className="mb-8 w-full p-4 bg-primary/20 border border-primary/30 rounded-2xl flex items-center gap-4 animate-in zoom-in">
             <Sparkles className="text-primary" />
             <p className="text-xs font-black uppercase italic">Chave de Parceiro Ativada: {referralCode}</p>
          </div>
        )}

        <div className="text-center mb-10">
           <div className="inline-block px-4 py-1 rounded-full border border-secondary/30 bg-secondary/10 text-secondary text-[10px] font-black uppercase tracking-widest mb-6">Janela de Ativação: 30 Dias</div>
           <h1 className="text-5xl font-black italic uppercase leading-none tracking-tighter">Ativar <br/><span className="text-primary">Serviço</span></h1>
        </div>

        <div className="w-full bg-white/5 border border-white/10 rounded-[2.5rem] p-10 mb-8 flex justify-between">
           <TimeUnit value={timeLeft.d} label="Dias" />
           <TimeUnit value={timeLeft.h} label="Horas" />
           <TimeUnit value={timeLeft.m} label="Min" />
           <TimeUnit value={timeLeft.s} label="Seg" />
        </div>

        <button 
          onClick={handleActivation}
          className="w-full h-24 bg-white text-[#0a0f1d] rounded-[2rem] font-black uppercase italic text-2xl flex items-center justify-center gap-4 shadow-2xl active:scale-95 transition-all"
        >
          Validar Chave <ChevronRight />
