          <Route path="/reportar" element={isAuthenticated ? <ReportAlert /> : <Navigate to="/login" />} />
          <Route path="/anunciar" element={isAuthenticated ? <PostAd /> : <Navigate to="/login" />} />
          <Route path="/moto-taxi" element={isAuthenticated ? <Layout><MotoTaxi /></Layout> : <Navigate to="/login" />} />
          <Route path="/blog" element={isAuthenticated ? <Layout><Blog /></Layout> : <Navigate to="/login" />} />
          <Route path="/patronos" element={isAuthenticated ? <Layout><Patrons /></Layout> : <Navigate to="/login" />} />
          <Route path="/roadmap" element={isAuthenticated ? <Layout><Roadmap /></Layout> : <Navigate to="/login" />} />

          {/* Painel do Administrador (Acesso direto via URL /admin) */}
          <Route path="/admin" element={<AdminDashboard />} />
        </Routes>
      </div>
    </Router>
  );
};

const SafetyGuard: React.FC = () => {
  const [speedAlert, setSpeedAlert] = useState(false);

  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => {
        const speed = pos.coords.speed || 0;
        if (speed > 15) setSpeedAlert(true);
        else setSpeedAlert(false);
      },
      () => {},
      { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  if (!speedAlert) return null;

  return (
    <div className="fixed inset-0 z-[9999] bg-[#e31d24] flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-300">
      <span className="material-symbols-outlined text-[120px] text-white mb-6 filled">front_hand</span>
