  const navigate = useNavigate();
  const location = useLocation();
  const [referralCode, setReferralCode] = useState<string>('');
  const [isActivating, setIsActivating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Tenta capturar o código da URL de forma ultra-robusta
    const params = new URLSearchParams(window.location.search);
    let code = params.get('ref');

    // Se não achou na query, tenta no Hash (comum em SPAs)
    if (!code) {
      const hashParts = window.location.hash.split('ref=');
      if (hashParts.length > 1) {
        code = hashParts[1].split('&')[0];
      }
    }

    if (code) {
      setReferralCode(code);
      console.log("Convite detectado via URL:", code);
    }
  }, [location]);

  const handleActivation = () => {
    if (!referralCode || referralCode.length < 3) {
      setError("Insira uma chave válida para continuar.");
      return;
    }

    setIsActivating(true);
    setError(null);

    // Simula a validação da malha
    setTimeout(() => {
      onLogin(); // Salva no LocalStorage via App.tsx
      console.log("Acesso validado com a chave:", referralCode);
      navigate('/dashboard'); 
