  const [copied, setCopied] = useState(false);

  const refreshData = async () => {
    setLoading(true);
    try {
      const [adsData, alertsData, statsData] = await Promise.all([
        db.ads.getAll(),
        db.alerts.getAll(),
        db.referrals.getStats()
      ]);
      setAds(adsData);
      setAlerts(alertsData);
      setStats(statsData);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { refreshData(); }, []);

