          </button>
          <button onClick={handleReset} className="size-10 bg-red-500/10 text-red-500 rounded-xl flex items-center justify-center border border-red-500/20"><RotateCcw size={18}/></button>
        </div>
      </header>

      <main className="p-6 space-y-6">
        <div className="grid grid-cols-2 gap-4">
           <SummaryCard label="Participantes" value={stats?.totalReferrals || 0} icon={<Users size={16}/>} color="text-blue-400" />
           <SummaryCard label="Créditos (R$)" value={stats?.adCredits.toFixed(0) || 0} icon={<DollarSign size={16}/>} color="text-green-500" />
           <SummaryCard label="Anúncios" value={ads.length} icon={<ShoppingBag size={16}/>} color="text-primary" />
           <SummaryCard label="Alertas" value={alerts.length} icon={<AlertTriangle size={16}/>} color="text-secondary" />
        </div>

        <div className="bg-white/5 rounded-3xl border border-white/10 overflow-hidden">
           <div className="flex border-b border-white/10">
              <TabBtn active={activeTab === 'testadores'} onClick={() => setActiveTab('testadores')} icon={<UserCheck size={16}/>} label="Usuários" />
              <TabBtn active={activeTab === 'ads'} onClick={() => setActiveTab('ads')} icon={<ClipboardList size={16}/>} label="Anúncios" />
              <TabBtn active={activeTab === 'alertas'} onClick={() => setActiveTab('alertas')} icon={<AlertTriangle size={16}/>} label="Alertas" />
           </div>

           <div className="p-8 min-h-[400px] flex flex-col items-center justify-center text-center space-y-4">
