                   <p className="italic text-sm">Monitoramento em tempo real ativo.</p>
                   <p className="text-[10px] uppercase font-black tracking-widest">Aguardando novas interações na rodovia...</p>
                </div>
              )}
           </div>
        </div>
      </main>

      {showInviteModal && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-6">
