import { 
  ArrowLeft,
  ShoppingBag,
  DollarSign,
  Trash2,
  AlertTriangle,
  Users,
  RotateCcw,
  UserCheck,
  ClipboardList,
  Search,
  Share2,
  X,
  BadgeCheck,
  Copy,
  Zap,
  ExternalLink,
  BarChart3,
  ShieldAlert
} from 'lucide-react';

const AdminDashboard: React.FC = () => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'testadores' | 'ads' | 'alertas'>('testadores');
  const [ads, setAds] = useState<StoredAd[]>([]);
  const [alerts, setAlerts] = useState<StoredAlert[]>([]);
  const [stats, setStats] = useState<ReferralStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [showInviteModal, setShowInviteModal] = useState(false);
  const [copied, setCopied] = useState(false);

  const refreshData = async () => {
    setLoading(true);
    try {
      const [adsData, alertsData, statsData] = await Promise.all([
        db.ads.getAll(),
        db.alerts.getAll(),
        db.referrals.getStats()
      ]);
      setAds(adsData);
      setAlerts(alertsData);
      setStats(statsData);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { refreshData(); }, []);

  const getInviteCode = () => "CONTRATO-232";

  const getInviteLink = () => {
    // Captura a base da URL removendo qualquer hash prévio
    const origin = window.location.origin;
    const pathname = window.location.pathname;
    const cleanPath = pathname.endsWith('/') ? pathname : pathname + '/';
    // Gera link compatível com HashRouter injetando ref como query do hash
    return `${origin}${cleanPath}#/login?ref=${getInviteCode()}`;
  };

  const handleWhatsAppInvite = () => {
    const link = getInviteLink();
    const text = `📊 *CREDENCIAMENTO: ECOSSISTEMA BR-232* 📊\n\nSua empresa foi selecionada para integrar a malha de serviços do eixo Luiz Gonzaga.\n\n🔗 *ATIVAR ACESSO CORPORATIVO:* ${link}\n\n🔑 *CHAVE DE ACESSO:* ${getInviteCode()}`;
    window.open(`https://wa.me/?text=${encodeURIComponent(text)}`, '_blank');
  };

  const handleReset = async () => {
    if (confirm("ATENÇÃO: A limpeza de dados removerá todos os registros operacionais. Confirmar?")) {
      await db.system.resetAll();
      window.location.reload();
    }
  };

  return (
    <div className="bg-[#0a0f1d] min-h-screen text-white font-display pb-32">
      <header className="p-6 border-b border-white/5 flex items-center justify-between sticky top-0 bg-[#0a0f1d]/80 backdrop-blur-xl z-50">
        <div className="flex items-center gap-4">
           <button onClick={() => navigate('/dashboard')} className="size-10 bg-white/5 rounded-xl flex items-center justify-center hover:bg-white/10 transition-colors"><ArrowLeft size={18}/></button>
           <div>
              <h1 className="text-xl font-black uppercase italic tracking-tighter">Gestão <span className="text-primary text-2xl">BR-232</span></h1>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-[0.3em]">Operações em Tempo Real</p>
           </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setShowInviteModal(true)} className="h-12 px-5 bg-primary text-white rounded-2xl flex items-center gap-2 font-black uppercase text-[10px] tracking-widest shadow-lg shadow-primary/20 transition-all hover:scale-105 active:scale-95">
            <Share2 size={14} /> Novo Credenciamento
          </button>
          <button onClick={handleReset} className="size-12 bg-red-500/10 text-red-500 rounded-2xl flex items-center justify-center border border-red-500/20 hover:bg-red-500 hover:text-white transition-all"><RotateCcw size={18}/></button>
        </div>
      </header>

      <main className="p-6 space-y-8 max-w-5xl mx-auto">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
           <SummaryCard label="Empresas/CPFs" value={stats?.totalReferrals || 0} icon={<Users size={18}/>} color="text-blue-400" />
           <SummaryCard label="Volume Créditos" value={`R$ ${stats?.adCredits.toFixed(0) || 0}`} icon={<DollarSign size={18}/>} color="text-green-500" />
           <SummaryCard label="Anúncios Ativos" value={ads.length} icon={<BarChart3 size={18}/>} color="text-primary" />
           <SummaryCard label="Incidentes" value={alerts.length} icon={<ShieldAlert size={18}/>} color="text-secondary" />
        </div>

        <div className="bg-white/5 rounded-[2.5rem] border border-white/10 overflow-hidden shadow-2xl">
           <div className="flex border-b border-white/10 bg-white/[0.02]">
              <TabBtn active={activeTab === 'testadores'} onClick={() => setActiveTab('testadores')} icon={<UserCheck size={16}/>} label="Parceiros" />
              <TabBtn active={activeTab === 'ads'} onClick={() => setActiveTab('ads')} icon={<ClipboardList size={16}/>} label="Inventário" />
              <TabBtn active={activeTab === 'alertas'} onClick={() => setActiveTab('alertas')} icon={<AlertTriangle size={16}/>} label="Logística" />
           </div>

           <div className="p-12 min-h-[400px] flex flex-col items-center justify-center text-center">
              {loading ? <RotateCcw className="animate-spin text-primary" size={32} /> : (
                <div className="space-y-4 max-w-xs opacity-40">
                   <div className="size-20 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-4 border border-white/10">
                      <BarChart3 size={32} />
                   </div>
                   <h3 className="font-black uppercase tracking-widest text-xs">Aguardando Ingestão de Dados</h3>
                   <p className="text-[10px] font-medium italic">A malha está operando sob protocolos de calibração dinâmica.</p>
                </div>
              )}
           </div>
        </div>
      </main>

      {showInviteModal && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="bg-[#161e31] w-full max-w-sm rounded-[3rem] border border-white/10 p-10 space-y-8 relative overflow-hidden">
             <div className="absolute top-0 right-0 p-12 opacity-5 -mr-8 -mt-8">
                <ExternalLink size={160} />
             </div>

             <div className="flex justify-between items-center relative z-10">
                <div className="size-12 bg-primary/20 rounded-2xl flex items-center justify-center text-primary border border-primary/20">
                   <Zap size={24} fill="currentColor" />
                </div>
                <button onClick={() => setShowInviteModal(false)} className="size-10 flex items-center justify-center rounded-2xl bg-white/5 hover:bg-white/10 transition-colors"><X size={20} /></button>
             </div>

             <div className="text-center relative z-10">
                <h2 className="text-3xl font-black italic uppercase tracking-tighter">Nova Credencial</h2>
                <p className="text-[10px] text-slate-500 font-bold uppercase mt-2 tracking-widest italic">Expansão de Malha Corporativa</p>
             </div>

             <div className="bg-white/5 p-6 rounded-[2rem] border border-white/10 text-center space-y-2 relative z-10">
                <p className="text-[9px] font-black uppercase text-primary tracking-[0.3em]">Chave de Ativação</p>
                <p className="text-3xl font-black italic uppercase tracking-widest text-white">{getInviteCode()}</p>
             </div>

             <div className="space-y-3 relative z-10">
                <button onClick={handleWhatsAppInvite} className="w-full h-16 bg-[#25D366] rounded-2xl font-black uppercase text-xs flex items-center justify-center gap-3 active:scale-95 transition-all shadow-lg shadow-green-500/10">Compartilhar WhatsApp <Share2 size={16}/></button>
                <button 
                  onClick={() => { 
                    navigator.clipboard.writeText(getInviteLink()); 
                    setCopied(true); 
                    setTimeout(()=>setCopied(false), 2000); 
                  }} 
                  className="w-full h-16 bg-white/5 rounded-2xl font-black uppercase text-[10px] flex items-center justify-center gap-3 border border-white/10 active:scale-95 transition-all hover:bg-white/10"
                >
                  {copied ? <BadgeCheck size={18} className="text-primary"/> : <><Copy size={18}/> Copiar Link Estruturado</>}
                </button>
                <button onClick={() => window.open(getInviteLink(), '_blank')} className="w-full h-14 bg-white/5 rounded-2xl font-black uppercase text-[10px] flex items-center justify-center gap-3 opacity-60 hover:opacity-100 transition-all">
                  <ExternalLink size={16}/> Testar Redirecionamento
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

const SummaryCard = ({ label, value, icon, color }: any) => (
  <div className="bg-white/5 p-5 rounded-[2rem] border border-white/5 backdrop-blur-sm transition-all hover:bg-white/[0.07]">
     <div className={`mb-3 p-2 bg-white/5 w-fit rounded-xl ${color}`}>{icon}</div>
     <p className="text-2xl font-black italic leading-none">{value}</p>
     <p className="text-[9px] font-black text-slate-500 uppercase mt-2 tracking-widest">{label}</p>
  </div>
);

const TabBtn = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex-1 flex flex-col items-center justify-center gap-1 py-5 text-[9px] font-black uppercase transition-all ${active ? 'bg-primary/10 text-primary border-b-2 border-primary' : 'text-slate-500 hover:text-white hover:bg-white/5'}`}>
    {icon} {label}
  </button>
);

export default AdminDashboard;

