import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Key, ChevronRight, RotateCcw, ShieldCheck, AlertCircle } from 'lucide-react';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const navigate = useNavigate();
  const location = useLocation();
  const [referralCode, setReferralCode] = useState<string>('');
  const [isActivating, setIsActivating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // FIX TÉCNICO: Captura do ref ignorando a rota do hash
    const hash = window.location.hash;
    const queryString = hash.includes('?') ? hash.split('?')[1] : '';
    const searchParams = new URLSearchParams(queryString);
    const code = searchParams.get('ref');

    if (code) {
      setReferralCode(code.toUpperCase());
      console.log("Credencial de parceria identificada:", code);
    }
  }, [location]);

  const handleActivation = () => {
    if (!referralCode || referralCode.length < 3) {
      setError("Credencial inválida ou expirada.");
      return;
    }

    setIsActivating(true);
    setError(null);

    setTimeout(() => {
      onLogin(); 
      navigate('/dashboard'); 
    }, 1000);
  };

  return (
    <div className="min-h-screen w-full bg-slate-50 dark:bg-[#0a0f1d] flex flex-col items-center justify-center p-6 font-display">
      <div className="w-full max-w-md bg-white dark:bg-[#161e31] rounded-[2.5rem] shadow-2xl border border-slate-200 dark:border-white/5 p-10 space-y-10 relative overflow-hidden">

        <div className="absolute top-0 left-0 w-full h-2 bg-primary"></div>

        <div className="text-center space-y-4">
          <div className="size-16 bg-primary/10 text-primary rounded-2xl flex items-center justify-center mx-auto border border-primary/10">
            <ShieldCheck size={32} />
          </div>
          <div>
            <h1 className="text-2xl font-black italic uppercase tracking-tighter">Credenciamento</h1>
            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1">Acesso ao Ecossistema BR-232</p>
          </div>
        </div>

        <div className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Chave de Acesso Corporativo</label>
            <div className="relative">
              <Key className="absolute left-5 top-1/2 -translate-y-1/2 text-primary" size={20} />
              <input 
                type="text"
                value={referralCode}
                onChange={(e) => {
                  setReferralCode(e.target.value.toUpperCase());
                  setError(null);
                }}
                placeholder="EX: CONTRATO-232"
                className="w-full h-18 bg-slate-50 dark:bg-slate-900 border-2 border-slate-100 dark:border-white/5 rounded-2xl pl-14 pr-6 text-lg font-black uppercase focus:border-primary focus:ring-0 outline-none transition-all placeholder:text-slate-300 dark:text-white"
              />
            </div>
          </div>

          {error && (
            <div className="flex items-center gap-2 text-secondary text-[10px] font-black uppercase bg-secondary/5 p-3 rounded-xl border border-secondary/10">
              <AlertCircle size={14} /> {error}
            </div>
          )}

          <button 
            onClick={handleActivation}
            disabled={isActivating || !referralCode}
            className="w-full h-20 bg-primary text-white rounded-2xl font-black uppercase italic text-sm flex items-center justify-center gap-3 shadow-lg shadow-primary/20 hover:brightness-110 active:scale-95 transition-all disabled:opacity-20"
          >
            {isActivating ? (
              <>
                <RotateCcw className="animate-spin" size={20} />
                <span>Validando...</span>
              </>
            ) : (
              <>
                Confirmar Credencial
                <ChevronRight size={20} />
              </>
            )}
          </button>
        </div>

        <p className="text-center text-[9px] font-bold text-slate-400 uppercase tracking-widest leading-relaxed">
          Seu acesso está sujeito aos termos do <br/>Plano de Expansão BR-232.
        </p>
      </div>

      <div className="mt-8 flex items-center gap-2 opacity-30 grayscale">
         <span className="text-[10px] font-black uppercase tracking-widest">Protocolo de Segurança Ativo</span>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
