              <span className="material-symbols-outlined" style={{ fontSize: '24px' }}>notifications</span>
              <span className="absolute top-2.5 right-2.5 size-2 bg-secondary rounded-full border border-background-light dark:border-surface-dark"></span>
            </button>
          </div>
        </div>
      </header>

      <main className="flex flex-col gap-6 p-4 pt-2 mb-32">
        {/* Painel da Via - Destaque */}
        <section aria-label="Status da Rodovia">
          <div className="rounded-3xl overflow-hidden bg-white dark:bg-surface-dark shadow-2xl border border-slate-100 dark:border-white/5">
            <div className="relative h-44 w-full">
              <div className="absolute inset-0 bg-cover bg-center" style={{ backgroundImage: "url('https://images.unsplash.com/photo-1545147986-a9d6f210df77?auto=format&fit=crop&q=80&w=800')" }}></div>
              <div className="absolute inset-0 bg-gradient-to-t from-background-dark/90 via-background-dark/40 to-transparent"></div>
              <div className="absolute bottom-4 left-4">
                <div className="flex items-center gap-2 mb-1">
                   <h2 className="text-white text-2xl font-black italic tracking-tighter uppercase">Painel da Via</h2>
                   <span className="px-2 py-0.5 bg-secondary text-white text-[10px] font-bold rounded italic animate-pulse">LIVE</span>
                </div>
                <p className="text-slate-300 text-[10px] uppercase font-bold tracking-widest">Sentido Interior • Luiz Gonzaga</p>
              </div>
            </div>
            <div className="p-5 flex flex-col gap-4">
              <div className="flex gap-4 items-center">
                <div className="shrink-0 size-14 rounded-2xl flex items-center justify-center shadow-inner" style={{ backgroundColor: `${roadStatus.color}20`, color: roadStatus.color }}>
                  <span className="material-symbols-outlined text-[32px] filled">traffic</span>
                </div>
                <div className="flex-1">
                  <h3 className="text-lg font-black leading-tight uppercase italic" style={{ color: roadStatus.color }}>{roadStatus.status}</h3>
                  <div className="flex items-center gap-1.5">
                    <span className="text-[10px] font-black text-primary uppercase bg-primary/10 px-1.5 rounded italic">Bizu da Via</span>
                    <p className="text-sm text-slate-500 dark:text-text-muted-dark font-medium leading-snug">{roadStatus.advice}</p>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-2">
                 <InfluenceBox icon={<TreeDeciduous size={14}/>} label="Tronco" sub="KM Direto" color="primary" />
                 <InfluenceBox icon={<GitBranch size={14}/>} label="Galhos" sub="Lindeiras" color="secondary" />
                 <InfluenceBox icon={<Waves size={14}/>} label="Raízes" sub="Zonas 100km" color="slate-500" />
              </div>
            </div>
          </div>
        </section>

        {/* Notícias e Inteligência */}
        <section className="bg-primary/5 rounded-3xl p-6 border border-primary/10">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2">
              <span className="material-symbols-outlined text-primary text-[24px]">google</span>
              <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-primary">Inteligência Luiz Gonzaga</h3>
            </div>
            <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Atualizado Agora</span>
          </div>
          {loading ? (
            <div className="animate-pulse space-y-3">
              <div className="h-3 bg-slate-200 dark:bg-white/10 rounded-full w-full"></div>
              <div className="h-3 bg-slate-200 dark:bg-white/10 rounded-full w-4/5"></div>
            </div>
          ) : (
            <div className="space-y-4">
              <p className="text-sm font-medium leading-relaxed text-slate-700 dark:text-slate-300">
                {news?.summary}
              </p>
            </div>
          )}
        </section>

        <section aria-label="Acesso Rápido">
          <div className="grid grid-cols-2 gap-4">
            <QuickLink to="/moto-taxi" icon="verified_user" label="Moto Segura" sub="Parceria Ativa" color="secondary" />
            <QuickLink to="/classificados" icon="shopping_bag" label="Feira da 232" sub="Negócios na Via" color="primary" />
          </div>
        </section>
      </main>
    </div>
  );
};

const InfluenceBox: React.FC<any> = ({ icon, label, sub, color }) => (
  <div className={`p-3 rounded-2xl border border-slate-200 dark:border-white/5 bg-white dark:bg-background-dark/50 flex flex-col items-center text-center shadow-sm`}>
     <div className={`text-${color} mb-1 opacity-80`}>{icon}</div>
     <p className="text-[8px] font-black uppercase text-slate-900 dark:text-white leading-none">{label}</p>
     <p className="text-[7px] font-bold text-slate-400 uppercase tracking-tighter mt-0.5">{sub}</p>
  </div>
);

const QuickLink: React.FC<{ to: string; icon: string; label: string; sub: string; color: string }> = ({ to, icon, label, sub, color }) => {
  const isPrimary = color === 'primary';
  return (
    <Link to={to} className={`flex flex-col p-5 rounded-3xl border transition-all active:scale-[0.98] shadow-sm ${isPrimary ? 'bg-primary/5 border-primary/10 text-primary' : 'bg-secondary/5 border-secondary/10 text-secondary'}`}>
      <span className="material-symbols-outlined text-[36px] mb-3">{icon}</span>
      <span className="font-black text-xs uppercase tracking-wider mb-1 italic">{label}</span>
      <span className="text-[10px] opacity-70 font-bold leading-tight uppercase tracking-tighter">{sub}</span>
    </Link>
  );
};

export default Home;
